use std::any::Any;
use std::error::Error;
use std::fmt;
use std::panic;

#[derive(Debug)]
struct ConfigError {
    message: String
}

impl fmt::Display for ConfigError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "Configuration setup failed: {}", self.message)
    }
}

impl Error for ConfigError {}

fn load_and_validate_config() -> Result<(), Box<dyn Error>> {
    let value = "";
    if value.is_empty() {
        return Err(Box::new(ConfigError { message: String::from("Value cannot be empty") }));
    }
    Ok(())
}

fn main() {
    panic::set_hook(Box::new(|info| {
        if let Some(payload) = info.payload().downcast_ref::<ConfigError>() {
            eprintln!("Caught expected application error: {}", payload);
        } else {
            eprintln!("An unknown panic occurred at location: {:?}", info.location());
        }
        std::process::exit(1);
    }));

    match load_and_validate_config() {
        Ok(_) => println!("Configuration loaded successfully."),
        Err(e) => {
            eprintln!("Application stopped due to error: {}", e);
            std::process::exit(1);
        }
    }
}

use std::panic;
use std::thread;
use std::time::Duration;

struct Matrix {
    data: Vec<f64>,
}

impl Matrix {
    fn new(size: usize) -> Self {
        Matrix { data: vec![0.0; size] }
    }

    fn simulate_computation(&self, input_value: f64) -> f64 {
        if input_value.is_infinite() || input_value.abs() > 1e300 {
            panic!("Input value caused an overflow or invalid state.");
        }
        let result = self.data.iter().sum::<f64>() * input_value;
        result
    }
}

fn main() {
    let matrix = Matrix::new(10);
    let bad_input = f64::MAX * 2.0;

    let result = panic::catch_unwind(|| {
        thread::sleep(Duration::from_millis(10));
        matrix.simulate_computation(bad_input)
    });

    match result {
        Ok(value) => println!("Computation succeeded: {}", value),
        Err(_) => {
            eprintln!("Caught a panic during computation.");
        }
    }
}

