use std::collections::VecDeque;
use std::sync::atomic::{AtomicBool, Ordering};

struct NetworkPacket {
    source_ip: String,
    destination_ip: String,
    payload_size: usize,
}

impl Drop for NetworkPacket {
    fn drop(&mut self) {
        println!("Cleaning up allocated packet data for {}", self.source_ip);
    }
}

struct PacketSniffer {
    processed_packets: VecDeque<Box<NetworkPacket>>,
    running: AtomicBool,
}

impl Default for PacketSniffer {
    fn default() -> Self { 
        Self { 
            processed_packets: VecDeque::new(), 
            running: AtomicBool::new(false)
        }
    }
}

impl Drop for PacketSniffer {
    fn drop(&mut self) {
        println!("--- Sniffer shutting down ---");
        self.running.store(false, Ordering::SeqCst);
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let mut sniffer = PacketSniffer::default();

    struct BufferAllocator {
        data: Option<Box<NetworkPacket>>
    }

    impl Drop for BufferAllocator {
        fn drop(&mut self) {
            if self.data.is_some() {
                println!("RAII cleanup triggered successfully.");
            }
        }
    }

    let mut buffer = BufferAllocator { data: None };
    buffer.data = Some(Box::new(NetworkPacket {
        source_ip: "192.168.1.1".to_string(),
        destination_ip: "8.8.8.8".to_string(),
        payload_size: 150,
    }));

    sniffer.processed_packets.push_back(buffer.data.take().unwrap());

    println!("Simulating packet capture cycle...");

    std::thread::sleep(std::time::Duration::from_millis(50));

    println!("Processing complete. Dropping sniffer to ensure cleanup.");
    Ok(())
}

use std::panic;
use std::thread;
use std::time::Duration;

struct GameState {
    is_running: bool,
}

impl GameState {
    fn new() -> Self {
        GameState { is_running: true }
    }

    fn run(&mut self) {
        println!("Starting simulation loop...");
        let mut counter = 0;
        while self.is_running && counter < 5 {
            thread::sleep(Duration::from_millis(10));
            counter += 1;
            println!("Tick {}", counter);
        }
        self.is_running = false;
    }
}

fn main() {
    let mut state = GameState::new();
    let result = panic::catch_unwind(panic::AssertUnwindSafe(|| {
        state.run();
    }));

    match result {
        Ok(_) => println!("Simulation finished gracefully."),
        Err(_e) => println!("Caught a simulated unexpected failure during execution.")
    }
}
